patch:
diff --git a/llvm/lib/Transforms/Scalar/InferAlignment.cpp b/llvm/lib/Transforms/Scalar/InferAlignment.cpp
index 93de58f7c8062..a08f70ac188a6 100644
--- a/llvm/lib/Transforms/Scalar/InferAlignment.cpp
+++ b/llvm/lib/Transforms/Scalar/InferAlignment.cpp
@@ -56,6 +56,13 @@ static bool tryToImproveAlign(
       return true;
     }
   }
+  if (match(I, m_Trunc(m_PtrToIntOrAddr(m_Value(PtrOp))))) {
+    Align ActualAlign = Fn(PtrOp, Align(1), Align(1));
+    if (Log2(ActualAlign) >= I->getType()->getScalarSizeInBits()) {
+      I->replaceAllUsesWith(Constant::getNullValue(I->getType()));
+      return true;
+    }
+  }

   IntrinsicInst *II = dyn_cast<IntrinsicInst>(I);
   if (!II)

tests.test_body:
define i64 @base(ptr %ptr) {
;
  %v1 = load i32, ptr %ptr, align 4
  %v3 = ptrtoint ptr %ptr to i64
  %v5 = and i64 %v3, 2
  ret i64 %v5
}

define i64 @best_alignment(ptr %ptr) {
;
  %v1 = load i32, ptr %ptr, align 8
  %v2 = load i32, ptr %ptr, align 16
  %v3 = ptrtoint ptr %ptr to i64
  %v5 = and i64 %v3, 15
  ret i64 %v5
}

declare void @func()

define i64 @negative_test(ptr %ptr) {
;
  %v3 = ptrtoint ptr %ptr to i64
  %v5 = and i64 %v3, 2
  call void @func()
  %v1 = load i32, ptr %ptr, align 4
  ret i64 %v5
}

define i64 @ptrtoaddr(ptr %ptr) {
;
  %v3 = ptrtoaddr ptr %ptr to i64
  %v1 = load i32, ptr %ptr, align 4
  %v5 = and i64 %v3, 2
  ret i64 %v5
}

define i64 @redundant_mask(ptr %ptr) {
;
  %load = load i32, ptr %ptr, align 4
  %int = ptrtoint ptr %ptr to i64
  %mask = and i64 %int, -4
  ret i64 %mask
}

define i64 @redundant_mask2(ptr %ptr) {
;
  %load = load i32, ptr %ptr, align 4
  %int = ptrtoint ptr %ptr to i64
  %mask = and i64 %int, -3
  ret i64 %mask
}

define i64 @not_redundant_mask(ptr %ptr) {
;
  %load = load i32, ptr %ptr, align 4
  %int = ptrtoint ptr %ptr to i64
  %mask = and i64 %int, -5
  ret i64 %mask
}

define i1 @trunc1_ptrtoint(ptr %ptr) {
;
  %load = load i16, ptr %ptr, align 2
  %int = ptrtoint ptr %ptr to i64
  %trunc = trunc i64 %int to i1
  ret i1 %trunc
}

define i1 @neg_trunc1_ptrtoint(ptr %ptr) {
;
  %load = load i8, ptr %ptr, align 1
  %int = ptrtoint ptr %ptr to i64
  %trunc = trunc i64 %int to i1
  ret i1 %trunc
}

define i4 @trunc4_ptrtoint(ptr %ptr) {
;
  %load = load i32, ptr %ptr, align 16
  %int = ptrtoint ptr %ptr to i64
  %trunc = trunc i64 %int to i4
  ret i4 %trunc
}

define i1 @trunc1_ptrtoaddr(ptr %ptr) {
;
  %load = load i16, ptr %ptr, align 2
  %int = ptrtoaddr ptr %ptr to i64
  %trunc = trunc i64 %int to i1
  ret i1 %trunc
}
